module top_module(
	input clk,
	input reset,
	output [3:0] count);logic [3:0] unused_count_reg;

	always @(posedge clk or posedge reset)
		if (reset) unused_count_reg = 4'b0000;
		else unused_count_reg = {unused_count_reg[2:0], ~unused_count_reg[3]};

	assign count = unused_count_reg;

endmodule
